export class RateLimiter {
  private tokens: number;
  private readonly maxTokens: number;
  private readonly refillRate: number; // tokens per second
  private lastRefill: number;

  constructor(maxTokens: number, refillRate: number) {
    this.maxTokens = maxTokens;
    this.tokens = maxTokens;
    this.refillRate = refillRate;
    this.lastRefill = Date.now();
  }

  /**
   * Try to consume one token. Returns true if allowed, false if rate-limited.
   */
  tryConsume(): boolean {
    this.refill();

    if (this.tokens > 0) {
      this.tokens -= 1;
      return true;
    }
    return false;
  }

  /**
   * Get the current number of available tokens.
   */
  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  /**
   * Reset the limiter to full capacity.
   */
  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefill = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefill;

    const newTokens = (elapsed * this.refillRate) / 1000;

    this.tokens = Math.min(this.tokens + newTokens, this.maxTokens);

    this.lastRefill = now;
  }
}

export interface Record {
  id: number;
  name: string;
  category: string;
  value: number;
}

export type Stage = (records: Record[]) => Record[];

export type Filter = (record: Record) => boolean;

export function andFilter(...filters: Filter[]): Filter {
  return (record) => filters.every((f) => f(record));
}

export function orFilter(...filters: Filter[]): Filter {
  return (record) => filters.some((f) => f(record));
}

export function notFilter(filter: Filter): Filter {
  return (record) => !filter(record);
}

export class Pipeline {
  private stages: Stage[] = [];
  private filters: Filter[] = [];

  addStage(stage: Stage): this {
    this.stages.push(stage);
    return this;
  }

  addFilter(filter: Filter): this {
    this.filters.push(filter);
    return this;
  }

  run(records: Record[]): Record[] {
    let result = [...records];
    if (this.filters.length > 0) {
      const combinedFilter = andFilter(...this.filters);
      result = result.filter(combinedFilter);
    }
    for (const stage of this.stages) {
      result = stage(result);
    }
    return result;
  }
}

export function doubleValues(records: Record[]): Record[] {
  return records.map((r) => ({ ...r, value: r.value * 2 }));
}

export interface CronSchedule {
  minutes: number[];
  hours: number[];
  daysOfMonth: number[];
  months: number[];
  daysOfWeek: number[];
  original: string;
}

export class CronParseError extends Error {
  constructor(message: string, public field?: string) {
    super(message);
    this.name = 'CronParseError';
  }
}

type FieldName = 'minute' | 'hour' | 'dayOfMonth' | 'month' | 'dayOfWeek';

const FIELD_RANGES: Record<FieldName, { min: number, max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function parseField(field: string, name: FieldName): number[] {
  const { min, max } = FIELD_RANGES[name];

  if (!field) {
    throw new CronParseError(`Field '${name}' is empty`, name);
  }

  // Split by commas (list)
  const parts = field.split(',');

  const valuesSet = new Set<number>();

  for (const part of parts) {
    // Check if part contains /
    const [rangePart, stepPart] = part.split('/');

    if (stepPart !== undefined) {
      if (!/^\d+$/.test(stepPart)) {
        throw new CronParseError(`Invalid step '${stepPart}' in field '${name}'`, name);
      }
    }
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    if (step <= 0) {
      throw new CronParseError(`Step must be positive in field '${name}'`, name);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (rangePart === '*') {
      rangeStart = min;
      rangeEnd = max;
    } else if (rangePart.includes('-')) {
      const [startStr, endStr] = rangePart.split('-');
      if (startStr === '' || endStr === '') {
        throw new CronParseError(`Invalid range '${rangePart}' in field '${name}'`, name);
      }
      if (!/^\d+$/.test(startStr) || !/^\d+$/.test(endStr)) {
        throw new CronParseError(`Invalid range numbers in '${rangePart}' in field '${name}'`, name);
      }
      rangeStart = parseInt(startStr, 10);
      rangeEnd = parseInt(endStr, 10);
      if (rangeStart > rangeEnd) {
        throw new CronParseError(`Range start greater than end in '${rangePart}' in field '${name}'`, name);
      }
      if (rangeStart < min || rangeEnd > max) {
        throw new CronParseError(`Range '${rangePart}' outside bounds in field '${name}'`, name);
      }
    } else {
      // Single number or '*'
      if (rangePart === '*') {
        rangeStart = min;
        rangeEnd = max;
      } else {
        if (!/^\d+$/.test(rangePart)) {
          throw new CronParseError(`Invalid number '${rangePart}' in field '${name}'`, name);
        }
        const val = parseInt(rangePart, 10);
        if (val < min || val > max) {
          throw new CronParseError(`Value '${val}' outside bounds in field '${name}'`, name);
        }
        // rangeStart == rangeEnd == val, step applies but meaningless here.
        rangeStart = val;
        rangeEnd = val;
      }
    }

    // Generate values from rangeStart to rangeEnd with step
    for (let v = rangeStart; v <= rangeEnd; v += step) {
      valuesSet.add(v);
    }
  }

  const values = Array.from(valuesSet);
  values.sort((a, b) => a - b);

  return values;
}

export function parseCron(expression: string): CronSchedule {
  if (typeof expression !== 'string') {
    throw new CronParseError('Expression must be a string');
  }
  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) {
    throw new CronParseError(`Invalid number of fields: expected 5 but got ${parts.length}`);
  }

  const [minuteStr, hourStr, dayOfMonthStr, monthStr, dayOfWeekStr] = parts;

  const minutes = parseField(minuteStr, 'minute');
  const hours = parseField(hourStr, 'hour');
  const daysOfMonth = parseField(dayOfMonthStr, 'dayOfMonth');
  const months = parseField(monthStr, 'month');
  const daysOfWeek = parseField(dayOfWeekStr, 'dayOfWeek');

  return {
    minutes,
    hours,
    daysOfMonth,
    months,
    daysOfWeek,
    original: expression,
  };
}

export interface Item {
  id: string;
  name: string;
  status: "active" | "archived";
  createdAt: number;
  updatedAt: number;
}

export interface Request {
  method: "GET" | "POST" | "PUT" | "DELETE" | string;
  headers: Record<string, string>;
  params: Record<string, string>;
  body?: unknown;
}

export interface Response {
  status: number;
  body: unknown;
}

const store = new Map<string, Item>();

export function resetStore(): void {
  store.clear();
}

export function getStore(): Map<string, Item> {
  return store;
}

function createResponse(status: number, success: boolean, dataOrError: unknown): Response {
  if (success) {
    return { status, body: { success, data: dataOrError } };
  }
  return { status, body: { success, error: dataOrError } };
}

function unauthorizedResponse(message: string = "Authorization required"): Response {
  return createResponse(401, false, message);
}

function invalidTokenResponse(): Response {
  return unauthorizedResponse("Invalid token");
}

function methodNotAllowedResponse(): Response {
  return createResponse(405, false, "Method not allowed");
}

function badRequestResponse(message: string): Response {
  return createResponse(400, false, message);
}

function notFoundResponse(): Response {
  return createResponse(404, false, "Item not found");
}

function itemExistsResponse(): Response {
  return createResponse(409, false, "Item already exists");
}

function checkAuthorization(headers: Record<string, string>): Response | null {
  const auth = headers["authorization"];
  if (!auth) return unauthorizedResponse();
  if (auth !== "Bearer valid-token") return invalidTokenResponse();
  return null;
}

function validateIdParam(params: Record<string, string>): string | Response {
  const id = params["id"];
  if (!id) return badRequestResponse("Validation failed: id parameter is required");
  return id;
}

function validateRequestBody(body: unknown): Record<string, unknown> | Response {
  if (!body || typeof body !== "object" || Array.isArray(body)) {
    return badRequestResponse("Request body is required");
  }
  return body as Record<string, unknown>;
}

function validateNameField(data: Record<string, unknown>): string | Response {
  const name = data["name"];
  if (!name || typeof name !== "string") {
    return badRequestResponse("Validation failed: name is required");
  }
  return name;
}

function validateStatusField(data: Record<string, unknown>): "active" | "archived" | null {
  const status = data["status"];
  if (status === "active" || status === "archived") {
    return status;
  }
  return null;
}

function handleGet(req: Request): Response {
  const idParam = req.params["id"];
  if (idParam) {
    const item = store.get(idParam);
    if (!item) return notFoundResponse();
    return createResponse(200, true, item);
  }
  const items = Array.from(store.values());
  return createResponse(200, true, items);
}

function handlePost(req: Request): Response {
  const bodyOrRes = validateRequestBody(req.body);
  if (bodyOrRes instanceof Object && "status" in bodyOrRes === false && "error" in bodyOrRes === false) {
    const data = bodyOrRes as Record<string, unknown>;
    const nameOrRes = validateNameField(data);
    if (typeof nameOrRes !== "string") return nameOrRes;
    const id = data["id"] as string | undefined;
    if (id && store.has(id)) return itemExistsResponse();

    const newId = id || `item-${Date.now()}`;
    const now = Date.now();
    const item: Item = {
      id: newId,
      name: nameOrRes,
      status: "active",
      createdAt: now,
      updatedAt: now,
    };
    store.set(newId, item);
    return createResponse(201, true, item);
  }
  return bodyOrRes as Response;
}

function handlePut(req: Request): Response {
  const idOrRes = validateIdParam(req.params);
  if (typeof idOrRes !== "string") return idOrRes;
  const item = store.get(idOrRes);
  if (!item) return notFoundResponse();

  const bodyOrRes = validateRequestBody(req.body);
  if (bodyOrRes instanceof Object && "status" in bodyOrRes === false && "error" in bodyOrRes === false) {
    const data = bodyOrRes as Record<string, unknown>;
    const updated: Item = {
      ...item,
      updatedAt: Date.now(),
    };
    const name = data["name"];
    if (typeof name === "string") {
      updated.name = name;
    }
    const status = validateStatusField(data);
    if (status) {
      updated.status = status;
    }
    store.set(idOrRes, updated);
    return createResponse(200, true, updated);
  }
  return bodyOrRes as Response;
}

function handleDelete(req: Request): Response {
  const idOrRes = validateIdParam(req.params);
  if (typeof idOrRes !== "string") return idOrRes;
  const item = store.get(idOrRes);
  if (!item) return notFoundResponse();
  store.delete(idOrRes);
  return createResponse(200, true, { deleted: idOrRes });
}

export function handleRequest(req: Request): Response {
  const authError = checkAuthorization(req.headers);
  if (authError) return authError;

  switch (req.method) {
    case "GET":
      return handleGet(req);
    case "POST":
      return handlePost(req);
    case "PUT":
      return handlePut(req);
    case "DELETE":
      return handleDelete(req);
    default:
      return methodNotAllowedResponse();
  }
}

import { deepMerge } from "../../starter/deep-merge.js";

describe("deepMerge", () => {
  it("merges nested objects recursively", () => {
    const target = { a: { b: 1, c: 2 }, d: 3 };
    const source = { a: { b: 10 }, d: 4 };
    const merged = deepMerge(target, source);
    expect(merged).toEqual({ a: { b: 10, c: 2 }, d: 4 });
  });

  it("replaces arrays entirely", () => {
    const target = { arr: [1, 2, 3] };
    const source = { arr: [4, 5] };
    const merged = deepMerge(target, source);
    expect(merged.arr).toEqual([4, 5]);
    expect(merged.arr).not.toBe(target.arr);
    expect(merged.arr).not.toBe(source.arr);
  });

  it("clones Date objects without sharing reference", () => {
    const d1 = new Date(2023, 0, 1);
    const d2 = new Date(2024, 0, 1);
    const target = { date: d1 };
    const source = { date: d2 };
    const merged = deepMerge(target, source);
    expect(merged.date).toEqual(d2);
    expect(merged.date).not.toBe(d2);
  });

  it("supports symbol keys", () => {
    const sym = Symbol("key");
    const target = { [sym]: 1 };
    const source = { [sym]: 2 };
    const merged = deepMerge(target, source);
    expect(merged[sym]).toBe(2);
  });

  it("skips forbidden prototype pollution keys", () => {
    const target = { safe: 1 };
    const source = {
      __proto__: { polluted: true },
      constructor: { crap: true },
      prototype: { nope: true },
      safe: 2,
    } as any;
    const merged = deepMerge(target, source);
    expect(merged.safe).toBe(2);
    expect((merged as any).polluted).toBeUndefined();
    expect((merged as any).constructor).not.toEqual({ crap: true });
    expect((merged as any).prototype).not.toEqual({ nope: true });
  });

  it("replaces target values with null when source is null", () => {
    const target = { a: 1, b: { c: 2 } };
    const source = { a: null, b: null };
    const merged = deepMerge(target, source);
    expect(merged).toEqual({ a: null, b: null });
  });

  it("skips undefined source values leaving target unchanged", () => {
    const target = { a: 1, b: { c: 2 } };
    const source = { a: undefined, b: { c: undefined, d: 3 } };
    const merged = deepMerge(target, source);
    expect(merged.a).toBe(1);
    expect(merged.b.c).toBe(2);
    expect(merged.b.d).toBe(3);
  });

  it("deeply merges multiple nested levels", () => {
    const target = { a: { b: { c: 1, d: 2 }, e: 3 }, f: 4 };
    const source = { a: { b: { c: 10 }, e: 30 }, f: 40 };
    const merged = deepMerge(target, source);
    expect(merged).toEqual({ a: { b: { c: 10, d: 2 }, e: 30 }, f: 40 });
  });

  it("replaces arrays in nested objects", () => {
    const target = { a: { b: [1, 2, 3] } };
    const source = { a: { b: [4, 5] } };
    const merged = deepMerge(target, source);
    expect(merged.a.b).toEqual([4, 5]);
  });

  it("does not mutate target or source objects", () => {
    const target = { a: { b: 1 }, c: [1, 2] };
    const source = { a: { d: 2 }, c: [3, 4] };
    const targetClone = JSON.parse(JSON.stringify(target));
    const sourceClone = JSON.parse(JSON.stringify(source));
    deepMerge(target, source);
    expect(target).toEqual(targetClone);
    expect(source).toEqual(sourceClone);
  });

  it("merges when target has undefined keys", () => {
    const target = { a: undefined };
    const source = { a: 1 };
    const merged = deepMerge(target, source);
    expect(merged.a).toBe(1);
  });

  it("properly merges when source has new keys with symbol", () => {
    const sym = Symbol("newKey");
    const target = {};
    const source = { [sym]: 123 };
    const merged = deepMerge(target, source);
    expect(merged[sym]).toBe(123);
  });

  it("handles source being empty and returns a copy of target", () => {
    const target = { a: 1, b: { c: 2} };
    const source = {} as any;
    const merged = deepMerge(target, source);
    expect(merged).toEqual(target);
    expect(merged).not.toBe(target);
    expect(merged.b).toEqual(target.b);
  });

  it("handles source keys with undefined values in nested objects", () => {
    const target = { a: { b: 1, c: 2 } };
    const source = { a: { b: undefined, c: 3 } };
    const merged = deepMerge(target, source);
    expect(merged.a.b).toBe(1);
    expect(merged.a.c).toBe(3);
  });

  it("replaces primitives in target with source primitives", () => {
    const target = { a: "old", b: 10, c: true };
    const source = { a: "new", b: 20, c: false };
    const merged = deepMerge(target, source);
    expect(merged).toEqual(source);
  });

  it("source array of Dates replaces target array", () => {
    const target = { arr: [new Date(1), new Date(2)] };
    const source = { arr: [new Date(3), new Date(4)] };
    const merged = deepMerge(target, source);
    expect(merged.arr.length).toBe(2);
    expect(merged.arr[0]).toEqual(new Date(3));
    expect(merged.arr[1]).toEqual(new Date(4));
    expect(merged.arr[0]).not.toBe(source.arr[0]);
  });
});
